# file: calculator.py

def add(a, b):
    return a + b

def subtract(a, b):
    return a - b

def multiply(a, b):
    return a * b

def divide(a, b):
    if b == 0:
        raise ValueError("Cannot divide by zero.")
    return a / b

def calculate(op, a, b):
    operations = {
        '+': add,
        '-': subtract,
        '*': multiply,
        '/': divide,
    }
    if op not in operations:
        raise ValueError(f"Unknown operator: {op}")
    return operations[op](a, b)
```

